export function calcJDN(year, month, day) {
  const a = Math.floor((14 - month) / 12);
  const y = year + 4800 - a;
  const m = month + 12 * a - 3;
  return day + Math.floor((153 * m + 2) / 5) + 365 * y
       + Math.floor(y / 4) - Math.floor(y / 100) + Math.floor(y / 400) - 32045;
}

export function calcShukuyo(year, month, day) {
  const key = String(year) + String(month);
  const row = SHUKUYO_TABLE[key];
  if (!row) return null;
  return row[day - 1] || null;
}

export function getShukuIdx(s) { return SHUKU_ORDER_ARR.indexOf(s); }

export function calcDayPillar(year, month, day) {
  const jdn = calcJDN(year, month, day);
  const idx0 = ((jdn + 49) % 60 + 60) % 60; // 0-indexed (0=甲子)
  const idx1 = idx0 + 1; // 1-indexed (1=甲子 〜 60=癸亥)
  return NIKUCHU_DATA[idx0];
}

export function getAnimalClass(idx) {
  var d = ANIMAL60_DATA[String(idx)]; return d ? d.class3 : null;
}

export function calcSeimei(surnameChars, givenChars) {
  const sStrokes = surnameChars.map(c => parseInt(c.strokes) || 0);
  const gStrokes = givenChars.map(c => parseInt(c.strokes) || 0);
  
  const sTotal = sStrokes.reduce((a, b) => a + b, 0);
  const gTotal = gStrokes.reduce((a, b) => a + b, 0);

  // 霊数：苗字が1文字のとき→天格に＋1、名前が1文字のとき→地格に＋1
  const sCount = surnameChars.filter(c => c.char && c.char.trim()).length;
  const gCount = givenChars.filter(c => c.char && c.char.trim()).length;
  const reisuu_s = sCount === 1 ? 1 : 0;  // 苗字霊数
  const reisuu_g = gCount === 1 ? 1 : 0;  // 名前霊数
  
  // 天格 = 苗字の全画数合計（＋苗字霊数）
  const tenku = sTotal + reisuu_s;
  
  // 人格 = 苗字の最後の字 + 名前の最初の字
  const jinku = (sStrokes[sStrokes.length - 1] || 0) + (gStrokes[0] || 0);
  
  // 地格 = 名前の全画数合計（＋名前霊数）
  const chiku = gTotal + reisuu_g;
  
  // 総格 = 全画数合計（霊数は含めない）
  const soku = sTotal + gTotal;

  // 外格 = 天格 + 地格 - 人格（対外的印象・社交運）
  const gaiku = (sTotal > 0 || gTotal > 0) ? tenku + chiku - jinku : 0;

  // 社会運 = 天格 + 名前の先頭1文字
  const shakai = (sTotal > 0 && gTotal > 0) ? tenku + (gStrokes[0] || 0) : 0;

  // 家庭運 = 苗字の末字 + 地格
  const katei = (sTotal > 0 && gTotal > 0) ? (sStrokes[sStrokes.length - 1] || 0) + chiku : 0;

  return { tenku, jinku, chiku, soku, gaiku, shakai, katei, sTotal, gTotal, reisuu_s, reisuu_g };
}

export function calcKakuFromChars(sChars, gChars) {
  const sS=sChars.map(c=>parseInt(c.strokes)||0);
  const gS=gChars.map(c=>parseInt(c.strokes)||0);
  const sT=sS.reduce((a,b)=>a+b,0), gT=gS.reduce((a,b)=>a+b,0);
  const sCnt=sChars.filter(c=>c.char&&c.char.trim()).length;
  const gCnt=gChars.filter(c=>c.char&&c.char.trim()).length;
  const rs=sCnt===1?1:0, rg=gCnt===1?1:0;
  return {
    tenku: sT+rs,
    jinku: (sS[sS.length-1]||0)+(gS[0]||0),
    chiku: gT+rg
  };
}

export function calcHexagram(year, month, day) {
  // Life Path from birth date → upper trigram
  const lp = calcLifePath(year, month, day);
  
  // Animal c124 → c125 (mod 60) → lower trigram
  const ymKey = String(year);
  const yearData = YEAR_MONTH[ymKey];
  if (!yearData) return null;
  const base = yearData[month - 1];
  const c124 = base + day;
  let idx = c124;
  while (idx > 120) idx -= 120;
  while (idx < 1) idx += 120;
  const c125 = idx <= 60 ? idx : idx - 60;
  
  let lowerTrigram = c125 % 8;
  if (lowerTrigram === 0) lowerTrigram = 8;
  
  let upperTrigram = lp % 8;
  if (upperTrigram === 0) upperTrigram = 8;
  
  const hexName = HEXAGRAM_MATRIX[lowerTrigram - 1][upperTrigram - 1];
  
  return {
    name: hexName,
    lp: lp,
    upper: upperTrigram,
    lower: lowerTrigram,
  };
}

export function calcBagua(tenku, jinku, chiku) {
  if (!tenku || !jinku || !chiku) return null;
  const tenYo  = tenku  % 2 === 1 ? '陽' : '陰';
  const jinYo  = jinku  % 2 === 1 ? '陽' : '陰';
  const chiYo  = chiku  % 2 === 1 ? '陽' : '陰';
  return BAGUA_TABLE.find(b => b.ten === tenYo && b.jin === jinYo && b.chi === chiYo) || null;
}

export function getNameBaguaIdx(tenku, jinku, chiku) {
  // 初爻=地格、二爻=人格、三爻=天格 の奇偶でインデックス1-8
  const chiYo = chiku % 2 === 1;
  const jinYo = jinku % 2 === 1;
  const tenYo = tenku % 2 === 1;
  // BAGUA_TABLE順: 乾(陽陽陽)=1, 兌(陰陽陽)=2, 離(陽陰陽)=3, 震(陰陰陽)=4
  //               巽(陽陽陰)=5, 坎(陰陽陰)=6, 艮(陽陰陰)=7, 坤(陰陰陰)=8
  if ( tenYo &&  jinYo &&  chiYo) return 1; // 乾
  if (!tenYo &&  jinYo &&  chiYo) return 2; // 兌
  if ( tenYo && !jinYo &&  chiYo) return 3; // 離
  if (!tenYo && !jinYo &&  chiYo) return 4; // 震
  if ( tenYo &&  jinYo && !chiYo) return 5; // 巽
  if (!tenYo &&  jinYo && !chiYo) return 6; // 坎
  if ( tenYo && !jinYo && !chiYo) return 7; // 艮
  return 8;                                  // 坤
}

export function sumDigits(n) {
  return String(Math.abs(n)).split('').reduce((a, c) => a + parseInt(c), 0);
}

export function calcLifePath(year, month, day) {
  const dateStr = String(year).padStart(4,'0') + String(month).padStart(2,'0') + String(day).padStart(2,'0');
  let total = dateStr.split('').reduce((a, c) => a + parseInt(c), 0);
  // Reduce, but keep master numbers 11, 22, 33
  while (total > 9 && total !== 11 && total !== 22 && total !== 33) {
    total = sumDigits(total);
  }
  return total;
}


// ─── メイン：名前・生年月日から全占い結果を計算 ───────────
export function calcAllFortune(
  surname: string,
  givenName: string,
  birthYear: number,
  birthMonth: number,
  birthDay: number,
  gender: '男' | '女'
) {
  // 姓名判断
  const surnameChars = surname.split('').map((c: string) => ({ char: c, strokes: (STROKE_DATA as any)[c] || 0 }));
  const givenChars   = givenName.split('').map((c: string) => ({ char: c, strokes: (STROKE_DATA as any)[c] || 0 }));
  const kaku = calcKakuFromChars(surnameChars, givenChars);
  const seimei = calcSeimei(surnameChars, givenChars);

  // 宿曜
  const shukuyo = calcShukuyo(birthYear, birthMonth, birthDay);

  // 日柱（動物占い）
  const dayPillar = calcDayPillar(birthYear, birthMonth, birthDay);
  const animalData = dayPillar ? (TABLE_120 as any)[String(dayPillar.idx)] : null;

  // 易（六十四卦）
  const hexResult = calcHexagram(birthYear, birthMonth, birthDay);

  return {
    name: surname + ' ' + givenName,
    gender,
    seimei: {
      tenku:    kaku.tenku,
      jinku:    kaku.jinku,
      chiku:    kaku.chiku,
      gaikaku:  seimei?.gaiku  ?? 0,
      soukaku:  seimei?.soku   ?? 0,
      shakaiun: seimei?.shakai ?? 0,
      kateun:   seimei?.katei  ?? 0,
    },
    shukuyo: shukuyo || '不明',
    animal: animalData ? animalData.animal : '不明',
    animalFull: animalData ? (animalData.color + 'の' + animalData.animal) : '不明',
    hex: hexResult ? hexResult.name : '不明',
  };
}
